import React, { useEffect, useState } from "react";
import api from "../../api/axios";
import { useAuth } from "../../context/AuthContext";
import "../admin/Admin.css";
import "./Student.css";

export default function StudentSchedule() {
  const { user } = useAuth();
  const [enrollments, setEnrollments] = useState([]);
  const [schedules, setSchedules]     = useState([]);
  const [classes, setClasses]         = useState([]);
  const [courses, setCourses]         = useState([]);
  const [filter, setFilter]           = useState("all");
  const [loading, setLoading]         = useState(true);

  useEffect(() => {
    if (!user) return;
    const fetchAll = async () => {
      setLoading(true);
      try {
        const [eRes, clsRes, courseRes] = await Promise.all([
          api.get("/student/enrollments"),
          api.get("/admin/classes").catch(() => ({ data:{ data:[] } })),
          api.get("/courses"),
        ]);

        const myEnrolls = (eRes.data.data || []).filter(e =>
          ["approved","enrolled"].includes(e.status)
        );
        const allClasses = clsRes.data.data || [];
        const allCourses = courseRes.data.data || [];

        setEnrollments(myEnrolls);
        setClasses(allClasses);
        setCourses(allCourses);

        // Lấy schedules của lớp đang học
        const myClassIds = [...new Set(myEnrolls.map(e => e.classId).filter(Boolean))];
        const allSchedules = [];
        for (const classId of myClassIds) {
          const r = await api.get(`/schedules/class/${classId}`)
            .catch(() => ({ data:{ data:[] } }));
          (r.data.data || []).forEach(s =>
            allSchedules.push({ ...s, classId })
          );
        }
        setSchedules(allSchedules);
      } catch(e) {
        console.error(e);
      } finally {
        setLoading(false);
      }
    };
    fetchAll();
  }, [user]);

  const getClass  = id => classes.find(c => Number(c.id) === Number(id));
  const getCourse = id => courses.find(c => Number(c.id) === Number(id));

  const now = new Date();
  const startOfWeek = new Date(now);
  startOfWeek.setDate(now.getDate() - now.getDay() + 1);
  const endOfWeek = new Date(startOfWeek);
  endOfWeek.setDate(startOfWeek.getDate() + 6);
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const endOfMonth   = new Date(now.getFullYear(), now.getMonth()+1, 0);

  const filteredSchedules = schedules.filter(s => {
    const d = new Date(s.NgayHoc || s.ngayHoc || s.date);
    if (filter === "week")  return d >= startOfWeek  && d <= endOfWeek;
    if (filter === "month") return d >= startOfMonth && d <= endOfMonth;
    return true;
  }).sort((a,b) =>
    new Date(a.NgayHoc||a.ngayHoc||a.date) -
    new Date(b.NgayHoc||b.ngayHoc||b.date)
  );

  const STATUS_BADGE = {
    scheduled:"badge-blue", ongoing:"badge-green",
    completed:"badge-gray", cancelled:"badge-red"
  };
  const STATUS_LABEL = {
    scheduled:"Đã lên lịch", ongoing:"Đang diễn ra",
    completed:"Hoàn thành",  cancelled:"Đã hủy"
  };

  if (loading) return <div className="page-loading"><div className="spinner"/></div>;

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Lớp & Lịch học</h1>
        <p>Thông tin các lớp và lịch học của bạn</p>
      </div>

      {/* ── Lớp đang tham gia ── */}
      <div className="section-card" style={{ marginBottom:20 }}>
        <h3 className="section-title">🏫 Lớp đang tham gia ({enrollments.length})</h3>
        {enrollments.length === 0
          ? <div className="empty-state"><p>Bạn chưa tham gia lớp học nào</p></div>
          : (
            <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(240px,1fr))", gap:12 }}>
              {enrollments.map(e => {
                const cls    = getClass(e.classId);
                const course = getCourse(e.courseId);
                if (!cls) return null;
                return (
                  <div key={e.id} style={{
                    border:"1.5px solid var(--gray-200)", borderRadius:"var(--radius)",
                    overflow:"hidden", transition:"all 0.2s"
                  }}>
                    <div style={{
                      background:"linear-gradient(135deg,var(--primary),var(--secondary))",
                      padding:"12px 14px", color:"#fff"
                    }}>
                      {course && (
                        <span style={{
                          background:"rgba(255,255,255,0.2)", padding:"2px 8px",
                          borderRadius:20, fontSize:"0.7rem", fontWeight:700
                        }}>{course.examType}</span>
                      )}
                      <p style={{ fontWeight:700, marginTop:4, fontSize:"0.95rem" }}>{cls.name}</p>
                      <p style={{ fontSize:"0.75rem", opacity:0.85 }}>{course?.title}</p>
                    </div>
                    <div style={{ padding:"10px 14px", background:"#fff" }}>
                      <p style={{ fontSize:"0.75rem", color:"var(--gray-500)" }}>
                        📅 {cls.startDate ? new Date(cls.startDate).toLocaleDateString("vi-VN") : "—"}
                        {" → "}
                        {cls.endDate ? new Date(cls.endDate).toLocaleDateString("vi-VN") : "—"}
                      </p>
                      <div style={{ marginTop:8 }}>
                        <div style={{ display:"flex", justifyContent:"space-between", fontSize:"0.72rem", color:"var(--gray-500)", marginBottom:4 }}>
                          <span>Tiến độ</span>
                          <span>{e.progress||0}%</span>
                        </div>
                        <div style={{ height:5, background:"var(--gray-100)", borderRadius:3, overflow:"hidden" }}>
                          <div style={{ height:"100%", width:`${e.progress||0}%`, background:"var(--primary)", borderRadius:3 }}/>
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )
        }
      </div>

      {/* ── Lịch học ── */}
      <div className="section-card">
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:16 }}>
          <h3 className="section-title" style={{ margin:0 }}>📅 Lịch học</h3>
          <div className="filter-tabs" style={{ margin:0 }}>
            {[["week","Tuần này"],["month","Tháng này"],["all","Tất cả"]].map(([k,l]) => (
              <button key={k} className={`filter-tab-btn ${filter===k?"active":""}`}
                onClick={() => setFilter(k)}>{l}</button>
            ))}
          </div>
        </div>

        {filteredSchedules.length === 0
          ? <div className="empty-state"><p>Không có lịch học nào</p></div>
          : filteredSchedules.map(s => {
            const cls    = getClass(s.classId);
            const course = getCourse(cls?.courseId);
            const dateStr = s.NgayHoc || s.ngayHoc || s.date;
            const d = dateStr ? new Date(dateStr) : null;
            const isToday = d?.toDateString() === now.toDateString();
            const title    = s.title    || s.TieuDe    || s.tieuDe    || "";
            const dateVal  = s.date     || s.NgayHoc   || s.ngayHoc   || null;
            const start    = s.startTime|| s.GioBatDau || s.gioBatDau || "";
            const end      = s.endTime  || s.GioKetThuc|| s.gioKetThuc|| "";
            const location = s.location || s.DiaDiem   || s.diaDiem   || "Tại trung tâm";
            const loai     = s.type     || s.LoaiLichHoc||s.loaiLichHoc||"online";
            const st       = s.status   || s.TrangThai || s.trangThai || "scheduled";

            return (
              <div key={s.id || s.ScheduleID} style={{
                display:"flex", gap:14, alignItems:"flex-start",
                padding:"12px 14px", borderRadius:10, marginBottom:8,
                background: isToday ? "var(--primary-light)" : "var(--gray-50)",
                borderLeft:`3px solid ${isToday ? "var(--primary)" : "var(--gray-200)"}`,
                transition:"all 0.15s"
              }}>
                <div style={{ textAlign:"center", minWidth:40, flexShrink:0 }}>
                  <span style={{ display:"block", fontSize:"1.3rem", fontWeight:700, color:"var(--gray-900)", lineHeight:1 }}>
                    {d ? d.getDate() : "—"}
                  </span>
                  <span style={{ display:"block", fontSize:"0.68rem", color:"var(--gray-500)", textTransform:"uppercase" }}>
                    {d ? d.toLocaleDateString("vi-VN",{month:"short"}) : ""}
                  </span>
                  {isToday && (
                    <div style={{ width:6, height:6, borderRadius:"50%", background:"var(--primary)", margin:"3px auto 0" }}/>
                  )}
                </div>
                <div style={{ flex:1 }}>
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                    <div>
                      <p style={{ fontWeight:600 }}>{title}</p>
                      <p style={{ fontSize:"0.78rem", color:"var(--gray-500)", marginTop:2 }}>
                        {cls?.name}{course ? ` · ${course.title}` : ""}
                      </p>
                    </div>
                    <span className={`badge ${STATUS_BADGE[st]||"badge-gray"}`}>
                      {STATUS_LABEL[st]||st}
                    </span>
                  </div>
                  <div style={{ display:"flex", gap:14, fontSize:"0.75rem", color:"var(--gray-500)", marginTop:6, flexWrap:"wrap" }}>
                    <span>⏰ {start?.slice(0,5)} – {end?.slice(0,5)}</span>
                    {loai === "online" && link
                      ? <span>🌐 <a href={link} target="_blank" rel="noreferrer"
                          style={{ color:"var(--primary)" }}>Tham gia online</a></span>
                      : <span>📍 {diaDiem || "Tại trung tâm"}</span>
                    }
                  </div>
                </div>
              </div>
            );
          })
        }
      </div>
    </div>
  );
}
